{
    const gert::Shape *x = context->GetInputShape(0);
    gert::Shape *y = context->GetOutputShape(0);

    const int64_t N = x->GetOriginShape().GetDim(0);
    const int64_t C = x->GetOriginShape().GetDim(1);
