    const int32_t stride      = context->GetAttrs()->GetAttr<int32_t>(1);
    const int32_t padding     = context->GetAttrs()->GetAttr<int32_t>(2);

    const int64_t Ho = (H + 2LL * padding - kernel_size) >= 0 ? ((H + 2LL * padding - kernel_size) / stride + 1) : 0;
    const int64_t Wo = (W + 2LL * padding - kernel_size) >= 0 ? ((W + 2LL * padding - kernel_size) / stride + 1) : 0;

